// Flatten Airtable records into usable objects
const records = $input.item.json.records || [];
return records.map(r => ({
  json: {
    record_id: r.id,
    business_name: r.fields.business_name || '',
    website: r.fields.website || '',
    domain: r.fields.domain || '',
    phone: r.fields.phone || '',
    category: r.fields.category || '',
    google_rating: r.fields.google_rating || null,
    review_count: r.fields.review_count || 0
  }
}));

const record = $input.item.json;

const systemPrompt = `You are a lead qualification specialist for an AI automation agency that sells workflow automation to small trades businesses (HVAC, plumbing, roofing contractors).
Your job is to analyze a business website and determine how likely that business is to need and benefit from automation services.

HIGH-value targets are businesses that:
- Have no online booking or scheduling system
- List only a phone number as their contact method with no form or chat
- Have vague, sparse service descriptions suggesting no structured processes
- Make no mention of software, apps, CRM, or customer portals
- Have emergency/24-7 claims but no automated system to back it up
- Show signs of being run manually (e.g. "call for a quote", "we'll get back to you")
- Have generic, template-looking websites with minimal custom content

LOW-value targets are businesses that:
- Mention ServiceTitan, Housecall Pro, Jobber, or other trades software
- Have an embedded booking widget or online scheduling
- Actively advertise their use of technology as a selling point
- Are clearly a franchise or large chain (likely already automated)

You must return ONLY a valid JSON object. No preamble, no explanation, no markdown.`;

const userPrompt = `Analyze this trades business website and score it.

Business: ${record.business_name}
Category: ${record.category || 'Unknown'}
Website URL: ${record.website}

Website Content:
"""
${record.website_text || '(no content retrieved)'}
"""

Return this exact JSON structure:
{
  "score": <integer 1-10>,
  "signals": [<array of strings, each describing a specific signal found, max 5>],
  "summary": "<one sentence explaining the score>",
  "has_booking_system": <boolean>,
  "mentions_software": <boolean>,
  "software_mentioned": "<name of software if found, else null>"
}`;

return [{ json: {
  ...record,
  claude_request_body: {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 500,
    system: systemPrompt,
    messages: [{ role: 'user', content: userPrompt }]
  }
}}];

// Sentinel -1 for double-failed Claude calls
const prevRecord = $('Build Claude Prompt').item.json;
return [{ json: {
  ...prevRecord,
  ai_score: -1,
  ai_signals: 'Claude API Error — both attempts failed',
  ai_summary: 'Scoring unavailable due to API error',
  website_fetch_status: prevRecord.website_fetch_status || 'Success'
}}];

// Parse Claude response — handles both success path and retry path
const response = $input.item.json;
const content = response.content?.[0]?.text || '';
const prevRecord = $('Build Claude Prompt').item.json;

let parsed;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = {
    score: 0,
    signals: ['Parse error — Claude returned invalid JSON'],
    summary: 'Failed to parse Claude response',
    has_booking_system: null,
    mentions_software: null,
    software_mentioned: null
  };
}

return [{ json: {
  ...prevRecord,
  ai_score: parsed.score || 0,
  ai_signals: Array.isArray(parsed.signals) ? parsed.signals.join(', ') : '',
  ai_summary: parsed.summary || '',
  has_booking_system: parsed.has_booking_system,
  mentions_software: parsed.mentions_software,
  software_mentioned: parsed.software_mentioned,
  website_fetch_status: prevRecord.website_fetch_status || 'Success'
}}];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: { skipped: true } }];
return [{ json: {
  slackUrl,
  slackBody: {
    text: `📊 *Workflow B Complete — AI Scoring Run*\nScoring batch finished. Check Airtable for updated Scored records with ai_score values.`
  }
}}];

const slackUrl = $env.SLACK_WEBHOOK_URL;
if (!slackUrl) return [{ json: {} }];
const err = $input.item.json;
return [{ json: {
  slackUrl,
  slackBody: { text: `🚨 *Workflow B Error*\n${err.execution?.error?.message || 'Unknown error'}` }
}}];
